  "questionProse": [
    "पहले से ही माफ़ी मांग रहा हूँ! 😈<br />\n    इनमें से कौन सा पासवर्ड इस पैटर्न से मेल खाता है?"
  ],
  "explanationProse": [
    "प्रोडक्शन में ऐसा कुछ भी न लिखें! 😅\n\n    यह पैटर्न कई पॉज़िटिव लुक-अहेड्स का उपयोग करके निम्नलिखित लागू करता है:\n    - कम से कम एक अपरकेस अक्षर: `(?=.*[A-Z])`\n    - कम से कम एक लोअरकेस अक्षर: `(?=.*[a-z])`\n    - कम से कम एक अंक: `(?=.*\\d)`\n    - कम से कम एक स्पेशल कैरेक्टर: `(?=.*[!@#$%^&*])`\n    - न्यूनतम लंबाई 8: `.{8,}`\n\n    लुक-अहेड्स पासवर्ड सत्यापन के लिए बिल्कुल सही हैं क्योंकि वे बिना कैरेक्टर्स को कंज्यूम किए कई मानदंडों की जाँच कर सकते हैं।\n\n    [पासवर्ड सत्यापन पैटर्न के बारे में और जानें](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Guide/Regular_Expressions/Assertions)"
  ]
}
